import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Article } from '../../../includes';
import { insureUtilStrings } from '../../utils';
import { Button } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 50,
    },
})
class _BlogView extends Component {
    constructor(props) {
        super(props);
        this.item = props.location.state;
    }
    
    render() {
        const {
            classes,
            [insureUtilStrings.backendBaseUrl] : baseUrl
        } = this.props;
        return (
            <div className={classes.root}>
                <Button
                    className={classes.backBtn}
                    color="secondary"
                    variant="contained"
                    onClick={()=>this.props.history.goBack()}>
                        Back
                    </Button>
                <Article 
                    {...this.item}
                    baseUrl={baseUrl}/>
            </div>
        );
    }
}


_BlogView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer}) => ({
    [insureUtilStrings.backendBaseUrl] : insureUtilReducer[insureUtilStrings.backendBaseUrl],
})

export const BlogView = connect(mapStateToProps)(withStyles(style)(_BlogView));
export {BlogView as default}